insert into public.requests (problem, desired_features, owner_id, created_at) values
  ('I want to know how much of my paycheck is left after fixed costs like rent and subscriptions, but doing the math every time is a hassle.', 'A tool where I enter my income and recurring costs once, and it shows my real ''free to spend'' amount for the month.', '1b3b2d99-cd41-4f8b-9805-63155203ff81', '2026-06-02T12:00:00Z'),
